import sys

def can_be_abc(s: str) -> bool:
    """Return True if s can become 'abc' with at most one swap."""
    if s == "abc":
        return True
    # Try all possible swaps of two positions
    for i in range(3):
        for j in range(i + 1, 3):
            # Create a copy and swap the two characters
            lst = list(s)
            lst[i], lst[j] = lst[j], lst[i]
            t = ''.join(lst)
            if t == "abc":
                return True
    return False

def main() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        s = data[i]
        out.append("YES" if can_be_abc(s) else "NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

