from typing import List

class Solution:
    def minExtraChar(self, s: str, dictionary: List[str]) -> int:
        n = len(s)
        dp = [0] * (n + 1)
        for i in range(1, n + 1):
            # default: treat current character as extra
            dp[i] = dp[i - 1] + 1
            # try to match any word ending at position i
            for word in dictionary:
                wlen = len(word)
                if i >= wlen and s[i - wlen:i] == word:
                    dp[i] = min(dp[i], dp[i - wlen])
        return dp[n]
```

