from typing import List

class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        colors = [0] * n
        ans = 0
        result = []
        for idx, color in queries:
            old = colors[idx]
            if old == color:
                result.append(ans)
                continue
            # left neighbor
            if idx > 0:
                neighbor = colors[idx-1]
                if old != 0 and old == neighbor:
                    ans -= 1
                if color != 0 and color == neighbor:
                    ans += 1
            # right neighbor
            if idx < n-1:
                neighbor = colors[idx+1]
                if old != 0 and old == neighbor:
                    ans -= 1
                if color != 0 and color == neighbor:
                    ans += 1
            # update
            colors[idx] = color
            result.append(ans)
        return result
